query:
{
  connectors(
    where: {
      conditionalAccessPolicies_NONE: {
        conditions: {
          includeUsers: ["All"]
          NOT: { excludeUsers: { eq: [] } }
          includeApplications: ["All"]
          clientAppTypes: ["all"]
          signInRiskLevels_INCLUDES: "high"
        }
        grantControls: { builtInControls: ["mfa"] }
        sessionControls: {
          signInFrequencyIsEnabled: { eq: true }
          signInFrequencyInterval: { eq: "everytime" }
        }
      }
    }
  ) {
    ...AssetFragment
  }
}
